import{_ as a,o as s,c as n,ae as i}from"./chunks/framework.CATMZqNR.js";const m=JSON.parse('{"title":"monad.ai, Cleaker, and Public Roots","description":"","frontmatter":{},"headers":[],"relativePath":"Monad-&&-Cleaker(me).md","filePath":"Monad-&&-Cleaker(me).md"}'),o={name:"Monad-&&-Cleaker(me).md"};function t(l,e,c,d,r,p){return s(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="monad-ai-cleaker-and-public-roots" tabindex="-1">monad.ai, Cleaker, and Public Roots <a class="header-anchor" href="#monad-ai-cleaker-and-public-roots" aria-label="Permalink to &quot;monad.ai, Cleaker, and Public Roots&quot;">​</a></h1><p>This page fixes a common confusion in the stack:</p><ul><li><code>.me</code> is the semantic kernel</li><li><code>monad.ai</code> runs monads: active execution agents</li><li><code>cleaker</code> is the binder that projects a <code>.me</code> into a namespace</li><li><code>cleaker.me</code> is the canonical public root.</li></ul><p><strong>Current implementation note:</strong> monad.ai now includes the NRP mesh layer: monads declare claimed namespaces, selectors constrain execution candidates, the scoring engine chooses the best claimant, and the bridge records outcomes for learning and analysis.</p><hr><h2 id="core-roles" tabindex="-1">Core Roles <a class="header-anchor" href="#core-roles" aria-label="Permalink to &quot;Core Roles&quot;">​</a></h2><h3 id="me" tabindex="-1"><code>.me</code> <a class="header-anchor" href="#me" aria-label="Permalink to &quot;\`.me\`&quot;">​</a></h3><p><code>.me</code> is the kernel.</p><p><strong>It owns:</strong></p><ul><li>identity derivation from seed</li><li>keys and secret scopes</li><li>semantic tree and memory log</li><li>snapshots, hydration, replay</li><li>cryptographic proof of identity</li></ul><p>Examples:</p><ul><li><code>me://self:read/profile</code></li><li><code>me://self:write/profile.name</code></li><li><code>me://self:explain/profile.netWorth</code></li></ul><h3 id="monad-ai" tabindex="-1"><code>monad.ai</code> <a class="header-anchor" href="#monad-ai" aria-label="Permalink to &quot;\`monad.ai\`&quot;">​</a></h3><p><code>monad.ai</code> runs monads: active agents that serve, resolve, and execute inside a namespace. It owns:</p><ul><li>serving namespace requests over HTTP</li><li>resolving namespaces from the <code>Host</code> header</li><li>persisting the kernel state via DiskStore</li><li>handling claim/open lifecycle</li><li>Monad process lifecycle, logs, status, and local execution</li><li>mesh discovery via <code>/.mesh/monads</code> and <code>/.mesh/resolve</code></li><li>adaptive route selection via scoring and decision logs</li></ul><p>A <strong>monad</strong> can run only for you on localhost, or it can be exposed publicly on a domain. The kernel is the storage. There is no separate database. A <strong>monad</strong> is not the namespace, not the host, and not the port. It is a <em>semantic execution route</em> chosen by the resolver:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>jabellae.cleaker.me/profile                 semantic path / meaning</span></span>
<span class="line"><span>jabellae.cleaker.me/photos/iphone           semantic path / meaning</span></span>
<span class="line"><span>jabellae.cleaker.me/.mesh/monads            internal Monad registry</span></span>
<span class="line"><span>jabellae.cleaker.me[monadlisa]/profile      technical execution override</span></span>
<span class="line"><span>monadlisa@127.0.0.1:8161                    Monad instance + endpoint</span></span></code></pre></div><p>The normal user-facing address has no monad selector:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>me://jabellae.cleaker.me/profile</span></span></code></pre></div><p>A monad selector is only a technical override. These still target the same semantic node:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>me://jabellae.cleaker.me[monadlisa]/profile</span></span>
<span class="line"><span>me://jabellae.cleaker.me[monadluis]/profile</span></span>
<span class="line"><span>me://jabellae.cleaker.me[device:macbook]/profile</span></span></code></pre></div><p>Named selectors force or identify execution. Device/tag/host selectors constrain the mesh candidates while leaving the semantic path unchanged.</p><h3 id="cleaker" tabindex="-1"><code>cleaker</code> <a class="header-anchor" href="#cleaker" aria-label="Permalink to &quot;\`cleaker\`&quot;">​</a></h3><p><code>cleaker</code> is the binder. It takes a <code>.me</code> instance and projects it into a namespace context. It handles the full bind lifecycle automatically:</p><ol><li>Ask <code>.me</code> to prove identity</li><li>Attempt to open the namespace</li><li>If the namespace does not exist yet, claim it</li><li>Reopen and hydrate the kernel with the returned memories</li></ol><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> node</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cleaker</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(me, {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  secret,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  namespace: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;username.cleaker.me&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  space: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;cleaker.me&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">await</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> node.ready</span></span></code></pre></div><p><code>cleaker</code> does not store anything. It does not own the identity. It connects <code>.me</code> to a namespace and hands control back.</p><p>Cleaker does not decide where a Monad runs. That belongs to NetGet.</p><h3 id="https-cleaker-me" tabindex="-1"><code>https://cleaker.me</code> <a class="header-anchor" href="#https-cleaker-me" aria-label="Permalink to &quot;\`https://cleaker.me\`&quot;">​</a></h3><p><code>cleaker.me</code> is not a different protocol. It is a <strong>public domain</strong> with Monads that act as a canonical public root — a common agreement where identities can be anchored publicly.</p><h6 id="that-means" tabindex="-1">That means: <a class="header-anchor" href="#that-means" aria-label="Permalink to &quot;That means:&quot;">​</a></h6><ul><li>infrastructure-wise, it is a public namespace served by Monads</li><li>semantically, it is a well-known root for public namespaces like <code>jabellae.cleaker.me</code> Any domain running compatible Monads can play this role. <code>cleaker.me</code> is the default, not the only option.</li></ul><hr><h1 id="deployment-roles" tabindex="-1">Deployment Roles <a class="header-anchor" href="#deployment-roles" aria-label="Permalink to &quot;Deployment Roles&quot;">​</a></h1><h3 id="local-only-monad" tabindex="-1">Local-only Monad <a class="header-anchor" href="#local-only-monad" aria-label="Permalink to &quot;Local-only Monad&quot;">​</a></h3><p>A local-only Monad runs only for you — on your laptop, your home server, your LAN. It does not need to be publicly accessible.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://suis-macbook-air.local:8161/</span></span></code></pre></div><p>You get the full kernel, the full memory log, the full identity — just not exposed to the internet.</p><h3 id="application-domain" tabindex="-1">Application domain <a class="header-anchor" href="#application-domain" aria-label="Permalink to &quot;Application domain&quot;">​</a></h3><p>An application domain — like <code>otherNamespace.com</code> — can run its own <code>monad.ai</code> and use it as the namespace root for its users. Users anchor their identity there:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>username.othernamespace.com</span></span></code></pre></div><p>The app does not need to use <code>cleaker.me</code>. It is its own notary.</p><h3 id="public-root" tabindex="-1">Public root <a class="header-anchor" href="#public-root" aria-label="Permalink to &quot;Public root&quot;">​</a></h3><p>A public root is a domain that exposes namespace behavior publicly and lets anyone anchor an identity under it. Examples:</p><ul><li><code>cleaker.me</code> — the canonical public root</li><li>any other domain running a public <code>monad.ai</code></li></ul><hr><h2 id="canonical-address-vs-web-projection" tabindex="-1">Canonical Address vs Web Projection <a class="header-anchor" href="#canonical-address-vs-web-projection" aria-label="Permalink to &quot;Canonical Address vs Web Projection&quot;">​</a></h2><p><code>me://</code> is the canonical semantic address. <code>https://</code> is one possible public projection of that address.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>me://username.cleaker.me:read/profile</span></span>
<span class="line"><span>https://username.cleaker.me/profile</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>me://username.othernamespace.com:read/profile</span></span>
<span class="line"><span>https://username.othernamespace.com/profile</span></span></code></pre></div><p>The semantic target is primary. The web URL is a projection chosen by the host.</p><hr><h2 id="key-spaces-and-privacy" tabindex="-1">Key Spaces and Privacy <a class="header-anchor" href="#key-spaces-and-privacy" aria-label="Permalink to &quot;Key Spaces and Privacy&quot;">​</a></h2><p>Topology does not imply publicity. A space can be replicated to multiple Monads — laptop, iPhone, home server, VM — and still remain completely private. The distinction is:</p><ul><li><strong>topology</strong> decides where the ciphertext exists</li><li><strong>audience</strong> decides who can open it So a key space may live on many Monads and still remain private if its audience is cryptographically closed.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T = {monadlisa, worker-a, phone-agent}  ← Monads where it lives</span></span>
<span class="line"><span>A = {jabellae}                         ← who can read it</span></span></code></pre></div><hr><h2 id="netget" tabindex="-1">NetGet <a class="header-anchor" href="#netget" aria-label="Permalink to &quot;NetGet&quot;">​</a></h2><p>NetGet is the physical placement and endpoint layer. It can place a Monad on a laptop, iPhone, Raspberry Pi, VM, relay, or localhost and resolve that placement into a current endpoint.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>me.monad[monad_id].endpoint(&quot;netget://iphone/monadlisa&quot;)</span></span>
<span class="line"><span>NetGet resolves that to http://10.0.0.12:8161</span></span></code></pre></div><p>The user asks for meaning. The resolver chooses a Monad route. NetGet handles the body that route runs in.</p><hr><h2 id="one-line-model" tabindex="-1">One-line Model <a class="header-anchor" href="#one-line-model" aria-label="Permalink to &quot;One-line Model&quot;">​</a></h2><ul><li><code>.me</code> holds the identity and the tree</li><li><code>cleaker</code> binds <code>.me</code> to a namespace</li><li><code>monad.ai</code> runs Monads that serve and execute inside that namespace</li><li><code>NetGet</code> places those Monads and resolves endpoints</li><li><code>cleaker.me</code> is one public root among many possible ones</li></ul><hr><h2 id="rule" tabindex="-1">Rule <a class="header-anchor" href="#rule" aria-label="Permalink to &quot;Rule&quot;">​</a></h2><ul><li>Every app can use <code>.me</code></li><li>Not every app needs <code>cleaker</code></li><li>Every public root can run <code>monad.ai</code></li><li><code>cleaker.me</code> is the canonical default, not the only option</li></ul>`,67)])])}const u=a(o,[["render",t]]);export{m as __pageData,u as default};
